INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5da6aed5-a1a3-4816-abd6-a81347100f05',
  '00000000-0000-0000-0000-000000000001',
  $escape$Mastering GDScript: A Beginner's Guide to Scene Trees and Node Signals$escape$,
  $escape$GDScript's scene tree is a fundamental concept for building games. Each node in the tree represents an object in the game world, and signals allow nodes to communicate with each other. To create a new node, use the `add_child()` method. For example, to add a sprite node to the current scene, use `add_child(Sprite.new())`. Signals can be connected using the `connect()` method. The `connect()` method takes two arguments: the signal name and the callback function.$escape$,
  $escape$var sprite = Sprite.new()
add_child(sprite)
sprite.connect("mouse_entered", self, "_on_sprite_mouse_entered")

def _on_sprite_mouse_entered():
    print("Mouse entered sprite")$escape$,
  $escape$gdscript$escape$,
