INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '62c0c7ff-99fe-4c8b-91ca-6d43309a26d9',
  '00000000-0000-0000-0000-000000000001',
  $escape$gdscript - Decoupling Game Logic from Engine Code$escape$,
  $escape$To separate game logic from engine code in gdscript, create a Godot Project singleton or a dedicated scene that manages game state. Use signals to communicate between nodes without exposing internal state. For example, a player node can emit a 'health_changed' signal when its health attribute changes. The game logic scene can then connect to this signal and update the UI accordingly.

Mod support can be achieved by loading custom scripts at runtime. Create a directory in the project's 'addons' folder and load the scripts using the 'GDScriptLoader' class. This allows modders to create and distribute custom scripts without modifying the game's core code.$escape$,
  $escape$extends Node

signal health_changed(value)

var current_health = 100

func _process(delta):
    if current_health <= 0:
        emit_signal("health_changed", 0)
    else:
        emit_signal("health_changed", current_health)$escape$,
  $escape$gdscript$escape$,
